1	default	{"autopublish_positive_reviews": true, "positive_review_min_rating": 4, "autopublish_questions": false, "require_review_categories": ["\\u043f\\u0440\\u043e\\u0431\\u0430/\\u043c\\u0430\\u0440\\u043a\\u0438\\u0440\\u043e\\u0432\\u043a\\u0430", "\\u043a\\u0430\\u043c\\u0435\\u043d\\u044c/\\u0432\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430", "\\u0437\\u0430\\u043c\\u043e\\u043a/\\u0437\\u0430\\u0441\\u0442\\u0435\\u0436\\u043a\\u0430", "\\u043a\\u0430\\u0447\\u0435\\u0441\\u0442\\u0432\\u043e/\\u0431\\u0440\\u0430\\u043a", "\\u0440\\u0430\\u0437\\u043c\\u0435\\u0440"], "require_review_risk_levels": ["medium", "high"], "forbidden_phrases": ["\\u043e\\u0431\\u043c\\u0435\\u043d\\u044f\\u0435\\u043c", "\\u0433\\u0430\\u0440\\u0430\\u043d\\u0442\\u0438\\u0440\\u0443\\u0435\\u043c \\u0432\\u043e\\u0437\\u0432\\u0440\\u0430\\u0442", "\\u043f\\u043e\\u0434\\u0434\\u0435\\u043b\\u043a\\u0430", "\\u0432\\u044b \\u043d\\u0435\\u043f\\u0440\\u0430\\u0432\\u044b", "\\u0441\\u0430\\u043c\\u0438 \\u0432\\u0438\\u043d\\u043e\\u0432\\u0430\\u0442\\u044b"], "max_auto_answer_chars": 900, "real_autopublish_enabled": true, "auto_generate_on_sync": true, "autopublish_local_templates": true, "autopublish_max_per_run": 10, "autopublish_interval_seconds": 900, "autopublish_pause_between_items_seconds": 8, "ai_generation_enabled": true, "ai_fallback_to_local_templates": true, "autopublish_matrix": {"WB": {"reviews": true, "questions": false}, "OZON": {"reviews": false, "questions": false}, "YM": {"reviews": false, "questions": false}}, "custom_system_prompt": "\\u0422\\u044b \\u043e\\u0442\\u0432\\u0435\\u0447\\u0430\\u0435\\u0448\\u044c \\u043e\\u0442 \\u0438\\u043c\\u0435\\u043d\\u0438 \\u044e\\u0432\\u0435\\u043b\\u0438\\u0440\\u043d\\u043e\\u0433\\u043e \\u0431\\u0440\\u0435\\u043d\\u0434\\u0430 KARATOV \\u043d\\u0430 \\u043e\\u0442\\u0437\\u044b\\u0432\\u044b \\u0438 \\u0432\\u043e\\u043f\\u0440\\u043e\\u0441\\u044b \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u0435\\u0439 \\u043c\\u0430\\u0440\\u043a\\u0435\\u0442\\u043f\\u043b\\u0435\\u0439\\u0441\\u043e\\u0432. \\u0422\\u043e\\u043d: \\u0441\\u043f\\u043e\\u043a\\u043e\\u0439\\u043d\\u044b\\u0439, \\u0442\\u0435\\u043f\\u043b\\u044b\\u0439, \\u043f\\u0440\\u043e\\u0444\\u0435\\u0441\\u0441\\u0438\\u043e\\u043d\\u0430\\u043b\\u044c\\u043d\\u044b\\u0439, \\u0431\\u0435\\u0437 \\u0441\\u043f\\u043e\\u0440\\u0430 \\u0438 \\u0431\\u0435\\u0437 \\u043e\\u0431\\u0432\\u0438\\u043d\\u0435\\u043d\\u0438\\u0439 \\u043a\\u043b\\u0438\\u0435\\u043d\\u0442\\u0430. \\u0413\\u043b\\u0430\\u0432\\u043d\\u044b\\u0439 \\u043f\\u0440\\u0438\\u043d\\u0446\\u0438\\u043f: \\u043e\\u0442\\u0432\\u0435\\u0442 \\u0434\\u043e\\u043b\\u0436\\u0435\\u043d \\u0431\\u044b\\u0442\\u044c \\u0443\\u043c\\u0435\\u0441\\u0442\\u0435\\u043d \\u043e\\u0446\\u0435\\u043d\\u043a\\u0435 \\u0438 \\u0441\\u043c\\u044b\\u0441\\u043b\\u0443 \\u043e\\u0442\\u0437\\u044b\\u0432\\u0430. \\u041d\\u0430 \\u043f\\u043e\\u0437\\u0438\\u0442\\u0438\\u0432\\u043d\\u044b\\u0435 \\u043e\\u0442\\u0437\\u044b\\u0432\\u044b \\u2014 \\u0431\\u043b\\u0430\\u0433\\u043e\\u0434\\u0430\\u0440\\u043d\\u043e\\u0441\\u0442\\u044c \\u0438 \\u0443\\u0441\\u0438\\u043b\\u0435\\u043d\\u0438\\u0435 \\u043f\\u043e\\u0437\\u0438\\u0442\\u0438\\u0432\\u043d\\u043e\\u0433\\u043e \\u043e\\u043f\\u044b\\u0442\\u0430. \\u041d\\u0430 \\u043d\\u0435\\u0433\\u0430\\u0442\\u0438\\u0432 \\u2014 \\u044d\\u043c\\u043f\\u0430\\u0442\\u0438\\u044f \\u0438 \\u0431\\u0435\\u0437\\u043e\\u043f\\u0430\\u0441\\u043d\\u044b\\u0439 \\u043c\\u0430\\u0440\\u0448\\u0440\\u0443\\u0442 \\u0440\\u0435\\u0448\\u0435\\u043d\\u0438\\u044f. \\u041d\\u0435 \\u0432\\u044b\\u0434\\u0443\\u043c\\u044b\\u0432\\u0430\\u0439 \\u0441\\u0432\\u043e\\u0439\\u0441\\u0442\\u0432\\u0430 \\u0442\\u043e\\u0432\\u0430\\u0440\\u0430, \\u043d\\u0435 \\u043e\\u0431\\u0435\\u0449\\u0430\\u0439 \\u0431\\u0435\\u0437\\u0443\\u0441\\u043b\\u043e\\u0432\\u043d\\u044b\\u0439 \\u0432\\u043e\\u0437\\u0432\\u0440\\u0430\\u0442/\\u043e\\u0431\\u043c\\u0435\\u043d, \\u043d\\u0435 \\u043f\\u0440\\u043e\\u0441\\u0438 \\u0432\\u043d\\u0435\\u0448\\u043d\\u0438\\u0435 \\u043a\\u043e\\u043d\\u0442\\u0430\\u043a\\u0442\\u044b \\u0438 \\u043d\\u0435 \\u043f\\u0435\\u0440\\u0435\\u0432\\u043e\\u0434\\u044c \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u044f \\u0432\\u043e \\u0432\\u043d\\u0435\\u0448\\u043d\\u0438\\u0435 \\u043a\\u0430\\u043d\\u0430\\u043b\\u044b. \\u041e\\u0442\\u0432\\u0435\\u0442 \\u043c\\u043e\\u0436\\u043d\\u043e \\u043f\\u043e\\u043a\\u0430\\u0437\\u044b\\u0432\\u0430\\u0442\\u044c \\u0442\\u043e\\u043b\\u044c\\u043a\\u043e \\u0435\\u0441\\u043b\\u0438 \\u043e\\u043d \\u0441\\u043e\\u043e\\u0442\\u0432\\u0435\\u0442\\u0441\\u0442\\u0432\\u0443\\u0435\\u0442 \\u043a\\u0430\\u0447\\u0435\\u0441\\u0442\\u0432\\u0443 10/10. \\u0421\\u043e\\u0431\\u043b\\u044e\\u0434\\u0430\\u0442\\u044c \\u0431\\u0435\\u0437\\u0443\\u043f\\u0440\\u0435\\u0447\\u043d\\u0443\\u044e \\u043e\\u0440\\u0444\\u043e\\u0433\\u0440\\u0430\\u0444\\u0438\\u044e \\u0438 \\u043f\\u0440\\u0430\\u0432\\u0438\\u043b\\u0430 \\u0440\\u0443\\u0441\\u0441\\u043a\\u043e\\u0433\\u043e \\u044f\\u0437\\u044b\\u043a\\u0430.", "review_prompt_template": "\\u0421\\u0433\\u0435\\u043d\\u0435\\u0440\\u0438\\u0440\\u0443\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442 \\u043d\\u0430 \\u043e\\u0442\\u0437\\u044b\\u0432 \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u044f. \\u0423\\u0447\\u0438\\u0442\\u044b\\u0432\\u0430\\u0439 \\u043e\\u0446\\u0435\\u043d\\u043a\\u0443, \\u0442\\u0435\\u043a\\u0441\\u0442, \\u043f\\u043b\\u044e\\u0441\\u044b/\\u043c\\u0438\\u043d\\u0443\\u0441\\u044b, \\u043a\\u0430\\u0442\\u0435\\u0433\\u043e\\u0440\\u0438\\u044e, \\u0440\\u0438\\u0441\\u043a \\u0438 \\u043f\\u0440\\u0430\\u0432\\u0438\\u043b\\u0430 KARATOV. \\u041e\\u0442\\u0432\\u0435\\u0442 \\u0434\\u043e\\u043b\\u0436\\u0435\\u043d \\u0431\\u044b\\u0442\\u044c \\u0433\\u043e\\u0442\\u043e\\u0432 \\u043a \\u043f\\u0443\\u0431\\u043b\\u0438\\u043a\\u0430\\u0446\\u0438\\u0438 \\u0442\\u043e\\u043b\\u044c\\u043a\\u043e \\u0435\\u0441\\u043b\\u0438 \\u043a\\u0430\\u0447\\u0435\\u0441\\u0442\\u0432\\u043e 10/10. \\u041e\\u0442\\u0432\\u0435\\u0442 \\u043d\\u0430 \\u043e\\u0442\\u0437\\u044b\\u0432 \\u0434\\u043e\\u043b\\u0436\\u0435\\u043d \\u043f\\u0440\\u0435\\u0434\\u043b\\u0430\\u0433\\u0430\\u0442\\u044c \\u0440\\u0435\\u0448\\u0435\\u043d\\u0438\\u0435, \\u0435\\u0441\\u043b\\u0438 \\u043a\\u043b\\u0438\\u0435\\u043d\\u0442 \\u0443\\u043a\\u0430\\u0437\\u044b\\u0432\\u0430\\u0435\\u0442 \\u043d\\u0430 \\u043a\\u0430\\u043a\\u043e\\u0439-\\u043b\\u0438\\u0431\\u043e \\u043d\\u0435\\u0434\\u043e\\u0447\\u0435\\u0442. \\u0412\\u0430\\u0436\\u043d\\u043e \\u0447\\u0442\\u043e\\u0431\\u044b \\u043e\\u0442\\u0432\\u0435\\u0442 \\u0431\\u044b\\u043b \\u0443\\u043c\\u0435\\u0441\\u0442\\u043d\\u044b\\u043c \\u0438 \\u0443\\u0447\\u0438\\u0442\\u044b\\u0432\\u0430\\u043b \\u043e\\u0446\\u0435\\u043d\\u043a\\u0443 \\u0442\\u0435\\u043a\\u0441\\u0442 \\u0442\\u0435\\u0433\\u0438 \\u0438 \\u043e\\u0431\\u0449\\u0438\\u0439 \\u043a\\u043e\\u043d\\u0442\\u0435\\u043a\\u0441\\u0442 ", "question_prompt_template": "\\u0421\\u0433\\u0435\\u043d\\u0435\\u0440\\u0438\\u0440\\u0443\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442 \\u043d\\u0430 \\u0432\\u043e\\u043f\\u0440\\u043e\\u0441 \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u044f. \\u041d\\u0435 \\u0432\\u044b\\u0434\\u0443\\u043c\\u044b\\u0432\\u0430\\u0439 \\u0445\\u0430\\u0440\\u0430\\u043a\\u0442\\u0435\\u0440\\u0438\\u0441\\u0442\\u0438\\u043a\\u0438 \\u0442\\u043e\\u0432\\u0430\\u0440\\u0430. \\u0415\\u0441\\u043b\\u0438 \\u0434\\u0430\\u043d\\u043d\\u044b\\u0445 \\u043d\\u0435 \\u0445\\u0432\\u0430\\u0442\\u0430\\u0435\\u0442 \\u2014 \\u043c\\u044f\\u0433\\u043a\\u043e \\u0443\\u043a\\u0430\\u0436\\u0438, \\u0447\\u0442\\u043e \\u0438\\u043d\\u0444\\u043e\\u0440\\u043c\\u0430\\u0446\\u0438\\u044f \\u0442\\u0440\\u0435\\u0431\\u0443\\u0435\\u0442 \\u043f\\u0440\\u043e\\u0432\\u0435\\u0440\\u043a\\u0438 \\u0438\\u043b\\u0438 \\u043d\\u0443\\u0436\\u043d\\u043e \\u043e\\u0440\\u0438\\u0435\\u043d\\u0442\\u0438\\u0440\\u043e\\u0432\\u0430\\u0442\\u044c\\u0441\\u044f \\u043d\\u0430 \\u043a\\u0430\\u0440\\u0442\\u043e\\u0447\\u043a\\u0443 \\u0442\\u043e\\u0432\\u0430\\u0440\\u0430.", "template_rules_text": "1) \\u0412\\u0441\\u0435\\u0433\\u0434\\u0430 \\u0443\\u0447\\u0438\\u0442\\u044b\\u0432\\u0430\\u0442\\u044c \\u043e\\u0446\\u0435\\u043d\\u043a\\u0443: 5\\u2605 \\u0431\\u0435\\u0437 \\u044f\\u0432\\u043d\\u043e\\u0439 \\u043f\\u0440\\u0435\\u0442\\u0435\\u043d\\u0437\\u0438\\u0438 = \\u0431\\u043b\\u0430\\u0433\\u043e\\u0434\\u0430\\u0440\\u043d\\u043e\\u0441\\u0442\\u044c \\u0438 \\u0442\\u0435\\u043f\\u043b\\u044b\\u0439 \\u043f\\u043e\\u0437\\u0438\\u0442\\u0438\\u0432, \\u0431\\u0435\\u0437 \\u0441\\u043b\\u043e\\u0432 \\u00ab\\u0436\\u0430\\u043b\\u044c\\u00bb, \\u00ab\\u043f\\u0440\\u043e\\u0431\\u043b\\u0435\\u043c\\u0430\\u00bb, \\u00ab\\u0441\\u0438\\u0442\\u0443\\u0430\\u0446\\u0438\\u044f\\u00bb, \\u00ab\\u043a\\u043e\\u043c\\u0430\\u043d\\u0434\\u0430 \\u043a\\u0430\\u0447\\u0435\\u0441\\u0442\\u0432\\u0430\\u00bb.\\n2) 5\\u2605 \\u0441 \\u043c\\u044f\\u0433\\u043a\\u0438\\u043c \\u0437\\u0430\\u043c\\u0435\\u0447\\u0430\\u043d\\u0438\\u0435\\u043c = \\u0431\\u043b\\u0430\\u0433\\u043e\\u0434\\u0430\\u0440\\u043d\\u043e\\u0441\\u0442\\u044c + \\u0430\\u043a\\u043a\\u0443\\u0440\\u0430\\u0442\\u043d\\u043e\\u0435 \\u043f\\u0440\\u0438\\u043d\\u044f\\u0442\\u0438\\u0435 \\u0437\\u0430\\u043c\\u0435\\u0447\\u0430\\u043d\\u0438\\u044f, \\u0431\\u0435\\u0437 \\u0434\\u0440\\u0430\\u043c\\u0430\\u0442\\u0438\\u0437\\u0430\\u0446\\u0438\\u0438.\\n3) 4\\u2605 = \\u0431\\u043b\\u0430\\u0433\\u043e\\u0434\\u0430\\u0440\\u043d\\u043e\\u0441\\u0442\\u044c + \\u043f\\u0440\\u0438\\u0437\\u043d\\u0430\\u043d\\u0438\\u0435 \\u043d\\u044e\\u0430\\u043d\\u0441\\u0430 + \\u0447\\u0442\\u043e \\u0438\\u043c\\u0435\\u043d\\u043d\\u043e \\u0443\\u0447\\u0442\\u0435\\u043c/\\u043f\\u0440\\u043e\\u0432\\u0435\\u0440\\u0438\\u043c.\\n4) 1\\u20133\\u2605 \\u0438\\u043b\\u0438 \\u044f\\u0432\\u043d\\u044b\\u0439 \\u0434\\u0435\\u0444\\u0435\\u043a\\u0442 = \\u044d\\u043c\\u043f\\u0430\\u0442\\u0438\\u044f/\\u0441\\u043e\\u0436\\u0430\\u043b\\u0435\\u043d\\u0438\\u0435 + \\u0431\\u0435\\u0437\\u043e\\u043f\\u0430\\u0441\\u043d\\u044b\\u0439 \\u043c\\u0430\\u0440\\u0448\\u0440\\u0443\\u0442 \\u0447\\u0435\\u0440\\u0435\\u0437 \\u0438\\u043d\\u0441\\u0442\\u0440\\u0443\\u043c\\u0435\\u043d\\u0442\\u044b \\u043c\\u0430\\u0440\\u043a\\u0435\\u0442\\u043f\\u043b\\u0435\\u0439\\u0441\\u0430/\\u043f\\u0440\\u043e\\u0432\\u0435\\u0440\\u043a\\u0443, \\u0431\\u0435\\u0437 \\u0441\\u043f\\u043e\\u0440\\u0430 \\u0441 \\u043a\\u043b\\u0438\\u0435\\u043d\\u0442\\u043e\\u043c.\\n5) \\u041f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u044b\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442 \\u043d\\u0430 Wildberries \\u043d\\u0435 \\u0434\\u043e\\u043b\\u0436\\u0435\\u043d \\u043f\\u0440\\u043e\\u0441\\u0438\\u0442\\u044c \\u043f\\u0440\\u0438\\u0441\\u043b\\u0430\\u0442\\u044c \\u0444\\u043e\\u0442\\u043e, \\u043d\\u0430\\u043f\\u0438\\u0441\\u0430\\u0442\\u044c/\\u043f\\u043e\\u0437\\u0432\\u043e\\u043d\\u0438\\u0442\\u044c, \\u043f\\u0435\\u0440\\u0435\\u0445\\u043e\\u0434\\u0438\\u0442\\u044c \\u0432\\u043e \\u0432\\u043d\\u0435\\u0448\\u043d\\u0438\\u0435 \\u043a\\u0430\\u043d\\u0430\\u043b\\u044b \\u0438\\u043b\\u0438 \\u0441\\u043e\\u0434\\u0435\\u0440\\u0436\\u0430\\u0442\\u044c \\u043a\\u043e\\u043d\\u0442\\u0430\\u043a\\u0442\\u044b.\\n6) \\u041d\\u0430 Ozon \\u0442\\u0430\\u043a\\u0436\\u0435 \\u043d\\u0435 \\u0438\\u0441\\u043f\\u043e\\u043b\\u044c\\u0437\\u043e\\u0432\\u0430\\u0442\\u044c \\u0432\\u043d\\u0435\\u0448\\u043d\\u0438\\u0435 \\u043a\\u043e\\u043d\\u0442\\u0430\\u043a\\u0442\\u044b, \\u0441\\u0441\\u044b\\u043b\\u043a\\u0438, \\u0442\\u0435\\u043b\\u0435\\u0444\\u043e\\u043d\\u044b, \\u0430\\u0434\\u0440\\u0435\\u0441\\u0430 \\u0438 \\u043d\\u0435\\u043f\\u043e\\u0434\\u0442\\u0432\\u0435\\u0440\\u0436\\u0434\\u0435\\u043d\\u043d\\u044b\\u0435 \\u043f\\u0440\\u0435\\u0432\\u043e\\u0441\\u0445\\u043e\\u0434\\u043d\\u044b\\u0435 \\u0441\\u0442\\u0435\\u043f\\u0435\\u043d\\u0438.\\n7) \\u041f\\u043e \\u043f\\u0440\\u043e\\u0431\\u0435 \\u043d\\u0435 \\u043f\\u0440\\u0435\\u0434\\u043b\\u0430\\u0433\\u0430\\u0442\\u044c \\u0432\\u043e\\u0437\\u0432\\u0440\\u0430\\u0442 \\u043f\\u0435\\u0440\\u0432\\u044b\\u043c \\u0448\\u0430\\u0433\\u043e\\u043c; \\u0441\\u043d\\u0430\\u0447\\u0430\\u043b\\u0430 \\u0441\\u043f\\u043e\\u043a\\u043e\\u0439\\u043d\\u0430\\u044f \\u043f\\u0440\\u043e\\u0432\\u0435\\u0440\\u044f\\u0435\\u043c\\u0430\\u044f \\u043b\\u043e\\u0433\\u0438\\u043a\\u0430: \\u043a\\u043b\\u0435\\u0439\\u043c\\u043e \\u043c\\u043e\\u0436\\u0435\\u0442 \\u0431\\u044b\\u0442\\u044c \\u043c\\u0435\\u043b\\u043a\\u0438\\u043c/\\u043b\\u0430\\u0437\\u0435\\u0440\\u043d\\u044b\\u043c, \\u044d\\u043b\\u0435\\u043c\\u0435\\u043d\\u0442\\u044b \\u043c\\u043e\\u0433\\u0443\\u0442 \\u0440\\u0430\\u0441\\u043f\\u043e\\u043b\\u0430\\u0433\\u0430\\u0442\\u044c\\u0441\\u044f \\u043e\\u0442\\u0434\\u0435\\u043b\\u044c\\u043d\\u043e, \\u0435\\u0441\\u0442\\u044c \\u0431\\u0438\\u0440\\u043a\\u0430/\\u0423\\u0418\\u041d/\\u043c\\u0430\\u0440\\u043a\\u0438\\u0440\\u043e\\u0432\\u043a\\u0430.\\n8) \\u041f\\u043e \\u044e\\u0432\\u0435\\u043b\\u0438\\u0440\\u043d\\u044b\\u043c \\u0438\\u0437\\u0434\\u0435\\u043b\\u0438\\u044f\\u043c \\u043d\\u0435 \\u043e\\u0431\\u0435\\u0449\\u0430\\u0442\\u044c \\u0431\\u0435\\u0437\\u0443\\u0441\\u043b\\u043e\\u0432\\u043d\\u044b\\u0439 \\u043e\\u0431\\u043c\\u0435\\u043d/\\u0432\\u043e\\u0437\\u0432\\u0440\\u0430\\u0442; \\u0444\\u043e\\u0440\\u043c\\u0443\\u043b\\u0438\\u0440\\u043e\\u0432\\u0430\\u0442\\u044c \\u0430\\u043a\\u043a\\u0443\\u0440\\u0430\\u0442\